def generate_all_points(mod):
    """
    Generate all unique points in the projective geometric space in
    the finite field with the given modulus.

    inputs:
        - mod: an integer representing the modulus

    Returns: a list of unique points, each is a tuple of 3 elements
    """
    points = []
    seen = set()
    for x_val in range(mod):
        for y_val in range(mod):
            for z_val in range(mod):
                if x_val == 0 and y_val == 0 and z_val == 0:
                    continue
                # Normalize: find first nonzero coord, multiply all by its inverse
                canonical = _normalize(x_val, y_val, z_val, mod)
                if canonical not in seen:
                    seen.add(canonical)
                    points.append((x_val, y_val, z_val))
    return points


def _normalize(x_val, y_val, z_val, mod):
    """Return a canonical form for a projective point."""
    for coord in (x_val, y_val, z_val):
        if coord % mod != 0:
            inv = pow(coord, mod - 2, mod)
            return ((x_val * inv) % mod, (y_val * inv) % mod, (z_val * inv) % mod)
    return (0, 0, 0)
